unit lipdecide;

{$mode objfpc}

interface

uses globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

function REALCOMPARE(A, B: real): COMPTYPE;
{ Compares two real numbers with respect to the six most significant digits }
var
  diff, magnitude, epsilon: real;
begin
  if (A = 0) and (B = 0) then
    exit(EQ);

  { Compute the magnitude for relative comparison }
  magnitude := abs(A);
  if abs(B) > magnitude then
    magnitude := abs(B);

  { Handle the case when both are very small or one is zero }
  if magnitude = 0 then
    exit(EQ);

  { Six significant digits means relative tolerance of 5e-6 }
  epsilon := magnitude * 0.000005;
  diff := A - B;

  if diff < -epsilon then
    REALCOMPARE := LT
  else if diff > epsilon then
    REALCOMPARE := GT
  else
    REALCOMPARE := EQ;
end;

{ Helper function: compute distance between two points }
function Distance(x1, y1, x2, y2: real): real;
begin
  Distance := sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
end;

{ Helper function: compute triangle area using the cross product formula }
function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := abs((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1)) / 2.0;
end;

{ Helper function: determine quadrant of a point (1-4, with priority rules) }
function GetQuadrant(px, py: real): integer;
begin
  { Priority: I, II, III, IV }
  { Quadrant I: x >= 0 and y >= 0 }
  { Quadrant II: x < 0 and y >= 0 }
  { Quadrant III: x <= 0 and y < 0 }
  { Quadrant IV: x > 0 and y < 0 }
  if (REALCOMPARE(px, 0) <> LT) and (REALCOMPARE(py, 0) <> LT) then
    GetQuadrant := 1
  else if (REALCOMPARE(px, 0) = LT) and (REALCOMPARE(py, 0) <> LT) then
    GetQuadrant := 2
  else if (REALCOMPARE(px, 0) <> GT) and (REALCOMPARE(py, 0) = LT) then
    GetQuadrant := 3
  else
    GetQuadrant := 4;
end;

{ Helper function: compute angle at vertex (x2,y2) formed by points (x1,y1)-(x2,y2)-(x3,y3) }
{ Returns angle in radians, or -1 if undefined (coincident points) }
function ComputeAngle(x1, y1, x2, y2, x3, y3: real): real;
var
  v1x, v1y, v2x, v2y: real;
  dot, cross, len1, len2: real;
begin
  v1x := x1 - x2;
  v1y := y1 - y2;
  v2x := x3 - x2;
  v2y := y3 - y2;

  len1 := sqrt(v1x * v1x + v1y * v1y);
  len2 := sqrt(v2x * v2x + v2y * v2y);

  { Check if either the first or last point coincides with vertex }
  if (REALCOMPARE(len1, 0) = EQ) or (REALCOMPARE(len2, 0) = EQ) then
  begin
    ComputeAngle := -1;
    exit;
  end;

  dot := v1x * v2x + v1y * v2y;
  cross := v1x * v2y - v1y * v2x;

  ComputeAngle := arctan2(abs(cross), dot);
end;

{ Helper function: compute circumradius of triangle with vertices (x1,y1), (x2,y2), (x3,y3) }
{ Returns a very large number if points are collinear }
function CircumRadius(x1, y1, x2, y2, x3, y3: real): real;
var
  a, b, c, area: real;
begin
  a := Distance(x1, y1, x2, y2);
  b := Distance(x2, y2, x3, y3);
  c := Distance(x3, y3, x1, y1);
  area := TriangleArea(x1, y1, x2, y2, x3, y3);

  if REALCOMPARE(area, 0) = EQ then
  begin
    { Collinear points - minimum enclosing circle has diameter = longest side }
    CircumRadius := a;
    if REALCOMPARE(b, CircumRadius) = GT then
      CircumRadius := b;
    if REALCOMPARE(c, CircumRadius) = GT then
      CircumRadius := c;
    CircumRadius := CircumRadius / 2.0;
  end
  else
    CircumRadius := (a * b * c) / (4.0 * area);
end;

{ Helper function: check if three points can be contained within or on a circle of given radius }
function CanContainInCircle(x1, y1, x2, y2, x3, y3, radius: real): boolean;
var
  minRadius: real;
begin
  { The minimum enclosing circle for three points has radius equal to either:
    1. The circumradius (if triangle is acute or right)
    2. Half the longest side (if triangle is obtuse or collinear) }
  minRadius := CircumRadius(x1, y1, x2, y2, x3, y3);

  { For obtuse triangles, check if half the longest side is smaller }
  { This is already handled in CircumRadius for collinear case }
  { For non-collinear, we need to check if the circumcircle is the minimum enclosing circle }
  { The circumcircle is the minimum enclosing circle only if all angles are <= 90 degrees }
  { Otherwise, the minimum enclosing circle has the longest side as diameter }

  { Actually, let's recompute properly: }
  { For any three points, the minimum enclosing circle is the smallest circle containing all three }
  { If the triangle is obtuse, the minimum enclosing circle has the longest side as diameter }

  CanContainInCircle := (REALCOMPARE(minRadius, radius) <> GT);
end;

{ Better helper: compute minimum enclosing circle radius for 3 points }
function MinEnclosingRadius(x1, y1, x2, y2, x3, y3: real): real;
var
  a, b, c, area: real;
  circumR, maxSide: real;
  cosA, cosB, cosC: real;
begin
  a := Distance(x2, y2, x3, y3); { side opposite to point 1 }
  b := Distance(x1, y1, x3, y3); { side opposite to point 2 }
  c := Distance(x1, y1, x2, y2); { side opposite to point 3 }
  area := TriangleArea(x1, y1, x2, y2, x3, y3);

  { Check for collinear points }
  if REALCOMPARE(area, 0) = EQ then
  begin
    { Minimum enclosing circle has diameter = longest side }
    maxSide := a;
    if REALCOMPARE(b, maxSide) = GT then maxSide := b;
    if REALCOMPARE(c, maxSide) = GT then maxSide := c;
    MinEnclosingRadius := maxSide / 2.0;
    exit;
  end;

  { Compute circumradius }
  circumR := (a * b * c) / (4.0 * area);

  { Check if triangle is obtuse by checking if any angle > 90 degrees }
  { Using law of cosines: cos(angle) = (b^2 + c^2 - a^2) / (2bc) }
  { Angle is obtuse if cos < 0 }

  { Check angle at point 1 (opposite to side a) }
  if REALCOMPARE(b*b + c*c, a*a) = LT then
  begin
    { Angle at point 1 is obtuse, minimum enclosing circle has side a as diameter }
    MinEnclosingRadius := a / 2.0;
    exit;
  end;

  { Check angle at point 2 (opposite to side b) }
  if REALCOMPARE(a*a + c*c, b*b) = LT then
  begin
    MinEnclosingRadius := b / 2.0;
    exit;
  end;

  { Check angle at point 3 (opposite to side c) }
  if REALCOMPARE(a*a + b*b, c*c) = LT then
  begin
    MinEnclosingRadius := c / 2.0;
    exit;
  end;

  { Triangle is acute or right, circumcircle is minimum enclosing circle }
  MinEnclosingRadius := circumR;
end;

{ Helper: distance from point (px, py) to line defined by (x1,y1) and (x2,y2) }
function PointToLineDistance(px, py, x1, y1, x2, y2: real): real;
var
  lineDist, dx, dy: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  lineDist := sqrt(dx * dx + dy * dy);

  if REALCOMPARE(lineDist, 0) = EQ then
  begin
    { Line is actually a point, return distance to that point }
    PointToLineDistance := Distance(px, py, x1, y1);
  end
  else
  begin
    { Distance from point to line using cross product formula }
    PointToLineDistance := abs(dy * px - dx * py + x2 * y1 - y2 * x1) / lineDist;
  end;
end;

{ LIC 1: Two consecutive points distance > LENGTH1 }
function EvaluateLIC1: boolean;
var
  i: integer;
  d: real;
begin
  EvaluateLIC1 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := Distance(X[i], Y[i], X[i+1], Y[i+1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      EvaluateLIC1 := true;
      exit;
    end;
  end;
end;

{ LIC 2: Three consecutive points cannot fit in circle of RADIUS1 }
function EvaluateLIC2: boolean;
var
  i: integer;
  r: real;
begin
  EvaluateLIC2 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    r := MinEnclosingRadius(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
    begin
      EvaluateLIC2 := true;
      exit;
    end;
  end;
end;

{ LIC 3: Three consecutive points form angle < PI-EPSILON or > PI+EPSILON }
function EvaluateLIC3: boolean;
var
  i: integer;
  angle: real;
begin
  EvaluateLIC3 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    angle := ComputeAngle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if angle >= 0 then { valid angle }
    begin
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
      begin
        EvaluateLIC3 := true;
        exit;
      end;
    end;
  end;
end;

{ LIC 4: Three consecutive points form triangle with area > AREA1 }
function EvaluateLIC4: boolean;
var
  i: integer;
  area: real;
begin
  EvaluateLIC4 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      EvaluateLIC4 := true;
      exit;
    end;
  end;
end;

{ LIC 5: Q_PTS consecutive points lie in more than QUADS quadrants }
function EvaluateLIC5: boolean;
var
  i, j, q: integer;
  quadPresent: array[1..4] of boolean;
  numQuads: integer;
begin
  EvaluateLIC5 := false;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for q := 1 to 4 do
      quadPresent[q] := false;

    for j := 0 to PARAMETERS.Q_PTS - 1 do
    begin
      q := GetQuadrant(X[i + j], Y[i + j]);
      quadPresent[q] := true;
    end;

    numQuads := 0;
    for q := 1 to 4 do
      if quadPresent[q] then
        Inc(numQuads);

    if numQuads > PARAMETERS.QUADS then
    begin
      EvaluateLIC5 := true;
      exit;
    end;
  end;
end;

{ LIC 6: Two consecutive points where X[j] - X[i] < 0 (j = i+1) }
function EvaluateLIC6: boolean;
var
  i: integer;
begin
  EvaluateLIC6 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i+1] - X[i], 0) = LT then
    begin
      EvaluateLIC6 := true;
      exit;
    end;
  end;
end;

{ LIC 7: N_PTS consecutive points, at least one > DIST from line joining first and last }
function EvaluateLIC7: boolean;
var
  i, j: integer;
  d, x1, y1, x2, y2: real;
  coincident: boolean;
begin
  EvaluateLIC7 := false;

  { Condition not met when NUMPOINTS < 3 }
  if NUMPOINTS < 3 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    x1 := X[i];
    y1 := Y[i];
    x2 := X[i + PARAMETERS.N_PTS - 1];
    y2 := Y[i + PARAMETERS.N_PTS - 1];

    { Check if first and last are coincident }
    coincident := (REALCOMPARE(Distance(x1, y1, x2, y2), 0) = EQ);

    for j := 1 to PARAMETERS.N_PTS - 2 do
    begin
      if coincident then
        d := Distance(X[i + j], Y[i + j], x1, y1)
      else
        d := PointToLineDistance(X[i + j], Y[i + j], x1, y1, x2, y2);

      if REALCOMPARE(d, PARAMETERS.DIST) = GT then
      begin
        EvaluateLIC7 := true;
        exit;
      end;
    end;
  end;
end;

{ LIC 8: Two points separated by K_PTS intervening points, distance > LENGTH1 }
function EvaluateLIC8: boolean;
var
  i: integer;
  d: real;
begin
  EvaluateLIC8 := false;

  { Condition not met when NUMPOINTS < 3 }
  if NUMPOINTS < 3 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    d := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      EvaluateLIC8 := true;
      exit;
    end;
  end;
end;

{ LIC 9: Three points separated by A_PTS and B_PTS, cannot fit in circle of RADIUS1 }
function EvaluateLIC9: boolean;
var
  i, j, k: integer;
  r: real;
begin
  EvaluateLIC9 := false;

  { Condition not met when NUMPOINTS < 5 }
  if NUMPOINTS < 5 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    r := MinEnclosingRadius(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
    begin
      EvaluateLIC9 := true;
      exit;
    end;
  end;
end;

{ LIC 10: Three points separated by C_PTS and D_PTS form angle < PI-EPSILON or > PI+EPSILON }
function EvaluateLIC10: boolean;
var
  i, j, k: integer;
  angle: real;
begin
  EvaluateLIC10 := false;

  { Condition not met when NUMPOINTS < 5 }
  if NUMPOINTS < 5 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;
    angle := ComputeAngle(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if angle >= 0 then { valid angle }
    begin
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
      begin
        EvaluateLIC10 := true;
        exit;
      end;
    end;
  end;
end;

{ LIC 11: Three points separated by E_PTS and F_PTS form triangle with area > AREA1 }
function EvaluateLIC11: boolean;
var
  i, j, k: integer;
  area: real;
begin
  EvaluateLIC11 := false;

  { Condition not met when NUMPOINTS < 5 }
  if NUMPOINTS < 5 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      EvaluateLIC11 := true;
      exit;
    end;
  end;
end;

{ LIC 12: Two points separated by G_PTS where X[j] - X[i] < 0 }
function EvaluateLIC12: boolean;
var
  i: integer;
begin
  EvaluateLIC12 := false;

  { Condition not met when NUMPOINTS < 3 }
  if NUMPOINTS < 3 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    if REALCOMPARE(X[i + PARAMETERS.G_PTS + 1] - X[i], 0) = LT then
    begin
      EvaluateLIC12 := true;
      exit;
    end;
  end;
end;

{ LIC 13: Two points separated by K_PTS, one pair > LENGTH1, another pair < LENGTH2 }
function EvaluateLIC13: boolean;
var
  i: integer;
  d: real;
  condA, condB: boolean;
begin
  EvaluateLIC13 := false;

  { Condition not met when NUMPOINTS < 3 }
  if NUMPOINTS < 3 then
    exit;

  condA := false;
  condB := false;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    d := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
      condA := true;
    if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then
      condB := true;
  end;

  EvaluateLIC13 := condA and condB;
end;

{ LIC 14: Three points separated by A_PTS and B_PTS,
          one set cannot fit in RADIUS1, another set can fit in RADIUS2 }
function EvaluateLIC14: boolean;
var
  i, j, k: integer;
  r: real;
  condA, condB: boolean;
begin
  EvaluateLIC14 := false;

  { Condition not met when NUMPOINTS < 5 }
  if NUMPOINTS < 5 then
    exit;

  condA := false;
  condB := false;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    r := MinEnclosingRadius(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
      condA := true;
    if (REALCOMPARE(r, PARAMETERS.RADIUS2) = LT) or (REALCOMPARE(r, PARAMETERS.RADIUS2) = EQ) then
      condB := true;
  end;

  EvaluateLIC14 := condA and condB;
end;

{ LIC 15: Three points separated by E_PTS and F_PTS,
          one set has area > AREA1, another set has area < AREA2 }
function EvaluateLIC15: boolean;
var
  i, j, k: integer;
  area: real;
  condA, condB: boolean;
begin
  EvaluateLIC15 := false;

  { Condition not met when NUMPOINTS < 5 }
  if NUMPOINTS < 5 then
    exit;

  condA := false;
  condB := false;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      condA := true;
    if REALCOMPARE(area, PARAMETERS.AREA2) = LT then
      condB := true;
  end;

  EvaluateLIC15 := condA and condB;
end;

procedure DECIDE;
var
  i, j: integer;
  allTrue: boolean;
begin
  { Step 1: Evaluate all LICs and set CMV }
  CMV[1] := EvaluateLIC1;
  CMV[2] := EvaluateLIC2;
  CMV[3] := EvaluateLIC3;
  CMV[4] := EvaluateLIC4;
  CMV[5] := EvaluateLIC5;
  CMV[6] := EvaluateLIC6;
  CMV[7] := EvaluateLIC7;
  CMV[8] := EvaluateLIC8;
  CMV[9] := EvaluateLIC9;
  CMV[10] := EvaluateLIC10;
  CMV[11] := EvaluateLIC11;
  CMV[12] := EvaluateLIC12;
  CMV[13] := EvaluateLIC13;
  CMV[14] := EvaluateLIC14;
  CMV[15] := EvaluateLIC15;

  { Step 2: Compute PUM off-diagonal elements from CMV and LCM }
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i <> j then
      begin
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD:    PUM[i, j] := CMV[i] and CMV[j];
          ORR:     PUM[i, j] := CMV[i] or CMV[j];
        end;
      end;
    end;
  end;

  { Step 3: Compute FUV from PUM }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
    begin
      { LIC should not hold back launch }
      FUV[i] := true;
    end
    else
    begin
      { Check if all elements in row i are true }
      allTrue := true;
      for j := 1 to 15 do
      begin
        if not PUM[i, j] then
        begin
          allTrue := false;
          break;
        end;
      end;
      FUV[i] := allTrue;
    end;
  end;

  { Step 4: Compute LAUNCH decision }
  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      break;
    end;
  end;
end;

end.
